'use client';

import type { Language, Theme, Difficulty } from '@/lib/minesweeper/types';
import { t } from '@/lib/minesweeper/i18n';

interface Props {
  minesLeft: number;
  elapsedTime: number;
  language: Language;
  theme: Theme;
  difficulty: Difficulty;
  playerName: string;
  onReset: () => void;
  onThemeToggle: () => void;
  onLangToggle: () => void;
  onLeaderboard: () => void;
  onBack: () => void;
}

function pad(n: number) {
  return String(Math.min(999, n)).padStart(3, '0');
}

const DIFF_KANJI: Record<Difficulty, string> = {
  beginner: '初',
  intermediate: '中',
  expert: '上',
};

export default function Header({
  minesLeft,
  elapsedTime,
  language,
  theme,
  difficulty,
  playerName,
  onReset,
  onThemeToggle,
  onLangToggle,
  onLeaderboard,
  onBack,
}: Props) {
  return (
    <>
      {/* ── MOBILE — top bar ── */}
      <header className="neu-header md:hidden w-full px-3 py-3 rounded-xl mb-3 flex items-center justify-between gap-2">
        <div className="flex items-center gap-2 min-w-[68px]">
          <button
            onClick={onBack}
            className="neu-btn-icon w-8 h-8 rounded-lg text-soft text-sm transition-all duration-150 active:scale-90"
            aria-label={t(language, 'back')}
          >
            ←
          </button>
          <div className="flex items-center gap-1">
            <span className="text-base">💣</span>
            <span className="font-mono text-base text-red-600 dark:text-red-400 tabular-nums">
              {pad(minesLeft)}
            </span>
          </div>
        </div>

        <button
          onClick={onReset}
          className="neu-btn-icon w-11 h-11 rounded-xl text-2xl transition-all duration-150 active:scale-90"
          title="Reset"
        >
          😊
        </button>

        <div className="flex items-center gap-2 justify-end">
          <span className="font-mono text-base text-app tabular-nums">{pad(elapsedTime)}</span>
          <button
            onClick={onLangToggle}
            className="neu-btn-icon w-8 h-8 rounded-lg font-mono text-[10px] text-soft active:scale-90 transition-all"
            title={t(language, 'language')}
          >
            {language === 'en' ? 'JP' : 'EN'}
          </button>
          <button
            onClick={onThemeToggle}
            className="neu-btn-icon w-8 h-8 rounded-lg text-sm text-soft active:scale-90 transition-all"
            title={t(language, 'theme')}
          >
            {theme === 'light' ? '☽' : '☀'}
          </button>
          <button
            onClick={onLeaderboard}
            className="neu-btn-icon w-8 h-8 rounded-lg text-sm active:scale-90 transition-all"
            title={t(language, 'leaderboard')}
          >
            🏆
          </button>
        </div>
      </header>

      {/* ── DESKTOP — vertical sidebar ── */}
      <aside className="hidden md:flex md:flex-col md:fixed md:left-6 md:top-1/2 md:-translate-y-1/2 md:w-56 md:gap-4 md:z-30">
        {/* Player card */}
        <div className="neu-card p-4 rounded-xl flex flex-col gap-1">
          <span className="font-mono text-[10px] tracking-[0.2em] text-muted uppercase">PLAYER</span>
          <span className="font-serif text-lg text-app truncate">{playerName}</span>
          <div className="flex items-center gap-2 mt-1">
            <span className="neu-inset w-7 h-7 rounded-md flex items-center justify-center font-serif text-sm text-matcha">
              {DIFF_KANJI[difficulty]}
            </span>
            <span className="font-serif text-xs text-soft">
              {language === 'jp' ? { beginner: '初級', intermediate: '中級', expert: '上級' }[difficulty]
                                  : t(language, difficulty as 'beginner' | 'intermediate' | 'expert')}
            </span>
          </div>
        </div>

        {/* Mine counter */}
        <div className="neu-inset p-4 rounded-xl flex items-center justify-between">
          <span className="flex items-center gap-2">
            <span className="text-lg">💣</span>
            <span className="font-serif text-xs text-muted tracking-wider uppercase">{t(language, 'mines')}</span>
          </span>
          <span className="font-mono text-2xl text-red-600 dark:text-red-400 tabular-nums">
            {pad(minesLeft)}
          </span>
        </div>

        {/* Timer */}
        <div className="neu-inset p-4 rounded-xl flex items-center justify-between">
          <span className="flex items-center gap-2">
            <span className="text-lg">⏱</span>
            <span className="font-serif text-xs text-muted tracking-wider uppercase">{t(language, 'time')}</span>
          </span>
          <span className="font-mono text-2xl text-app tabular-nums">{pad(elapsedTime)}</span>
        </div>

        {/* Reset button */}
        <button
          onClick={onReset}
          className="neu-btn-raised py-3 rounded-xl flex items-center justify-center gap-2 active:scale-95 transition-all"
        >
          <span className="text-xl">😊</span>
          <span className="font-serif text-sm text-app">{t(language, 'retry')}</span>
        </button>

        {/* Controls row */}
        <div className="flex gap-2">
          <button
            onClick={onLangToggle}
            className="neu-btn-icon flex-1 h-10 rounded-lg font-mono text-xs text-soft active:scale-95 transition-all"
            title={t(language, 'language')}
          >
            {language === 'en' ? 'JP' : 'EN'}
          </button>
          <button
            onClick={onThemeToggle}
            className="neu-btn-icon flex-1 h-10 rounded-lg text-sm text-soft active:scale-95 transition-all"
            title={t(language, 'theme')}
          >
            {theme === 'light' ? '☽ Dark' : '☀ Light'}
          </button>
        </div>

        {/* Leaderboard */}
        <button
          onClick={onLeaderboard}
          className="neu-btn-raised py-2.5 rounded-lg flex items-center justify-center gap-2 active:scale-95 transition-all"
        >
          <span>🏆</span>
          <span className="font-serif text-sm text-soft">{t(language, 'leaderboard')}</span>
        </button>

        {/* Back */}
        <button
          onClick={onBack}
          className="neu-btn-subtle py-1.5 rounded-lg font-serif text-xs text-muted hover:text-app transition-colors"
        >
          ← {t(language, 'difficultyLabel')}
        </button>
      </aside>
    </>
  );
}
