'use client';

import { useState } from 'react';
import type { Language, Difficulty } from '@/lib/minesweeper/types';
import { t } from '@/lib/minesweeper/i18n';

interface Props {
  status: 'won' | 'lost';
  time: number;
  playerName: string;
  language: Language;
  difficulty: Difficulty;
  onRetry: () => void;
  onSave: (name: string) => void;
}

export default function GameOverlay({ status, time, playerName, language, difficulty, onRetry, onSave }: Props) {
  const [name, setName] = useState(playerName);
  const [saved, setSaved] = useState(false);

  const handleSave = () => {
    if (saved) return;
    onSave(name.trim() || playerName);
    setSaved(true);
  };

  const isWin = status === 'won';

  const diffLabel = {
    beginner: language === 'jp' ? '初級' : 'Beginner',
    intermediate: language === 'jp' ? '中級' : 'Intermediate',
    expert: language === 'jp' ? '上級' : 'Expert',
  }[difficulty];

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center p-4"
         style={{ backgroundColor: 'rgba(0,0,0,0.45)', backdropFilter: 'blur(4px)' }}>
      <div className="neu-card p-8 rounded-2xl w-full max-w-xs flex flex-col gap-5 animate-fade-in">
        {/* Result */}
        <div className="text-center">
          <div className="text-5xl mb-2">{isWin ? '🎉' : '💥'}</div>
          <h2 className="font-serif text-2xl tracking-wider text-stone-700 dark:text-washi-200">
            {isWin ? t(language, 'youWin') : t(language, 'gameOver')}
          </h2>
          <p className="font-mono text-sm text-stone-400 dark:text-stone-500 mt-1">{diffLabel}</p>
        </div>

        {/* Time */}
        {isWin && (
          <div className="text-center neu-inset px-4 py-3 rounded-xl">
            <p className="font-serif text-xs text-stone-400 dark:text-stone-500 mb-0.5">
              {t(language, 'yourTime')}
            </p>
            <p className="font-mono text-3xl font-bold text-stone-700 dark:text-washi-200">
              {time}<span className="text-base ml-1">{t(language, 'seconds')}</span>
            </p>
          </div>
        )}

        {/* Save score */}
        {isWin && !saved && (
          <div className="flex flex-col gap-2">
            <input
              type="text"
              value={name}
              onChange={(e) => setName(e.target.value)}
              maxLength={20}
              className="neu-input px-4 py-2 rounded-xl font-serif text-sm outline-none w-full
                         text-stone-700 dark:text-washi-100"
            />
            <button
              onClick={handleSave}
              className="neu-btn-primary py-2 px-4 rounded-xl font-serif tracking-wider
                         transition-all duration-200 active:scale-95"
            >
              {t(language, 'saveScore')}
            </button>
          </div>
        )}

        {isWin && saved && (
          <p className="text-center font-serif text-sm text-matcha dark:text-matcha">
            {language === 'jp' ? '保存しました！' : 'Score saved!'}
          </p>
        )}

        {/* Retry */}
        <button
          onClick={onRetry}
          className="neu-btn-raised py-2 px-4 rounded-xl font-serif tracking-wider
                     transition-all duration-200 active:scale-95 text-stone-600 dark:text-washi-300"
        >
          {t(language, 'retry')}
        </button>
      </div>
    </div>
  );
}
